import collections,re
VOW='aeiou'
def split_pref(s):
    m=re.match(r'^(s-|s̥-)?(.*)$',s); return m.group(1) or '', m.group(2)
def first_vowel_span(root):
    i=0
    while i<len(root) and root[i] not in VOW: i+=1
    if i>=len(root): return None
    j=i+1
    while j<len(root) and root[j]==':': j+=1
    return i,j  # vowel start, end(after length)
def count_vowels(root):
    return sum(1 for c in root if c in VOW)
def redup(s):
    p,root=split_pref(s)
    fv=first_vowel_span(root)
    if fv is None: return s
    i,j=fv
    onset=root[:i]; vowel=root[i:j].replace(':','')
    R=onset+vowel  # reduplicant, length removed
    nv=count_vowels(root)
    if nv>=2:
        # syncopate base first vowel
        base=root[:i]+root[j:]
    else:
        base=root[:i]+vowel+root[j:]  # keep base but shorten long vowel
    return p+R+base
def dereplicate(pl_stem, sg_hint):
    # if we know sg exists but not; just return best guess by removing reduplicant
    return pl_stem
def endvow(s): return s[-1] in VOW or s[-1] in 'ĭă'
def add_fut(s):
    if s.endswith('ĭ'): return s[:-1]+'id'
    if s.endswith('ă'): return s[:-1]+'ad'
    if s[-1] in VOW: return s+'d'
    return s+'ad'
def add_imp(s):
    if s.endswith('ĭ'): return s[:-1]+'iñ'
    if s.endswith('ă'): return s[:-1]+'iñ'
    if s.endswith('s̥'): return s[:-2]+'siñ'
    if s[-1] in VOW: return s+'ñ'
    return s+'iñ'
def strip_fut(f):
    if f.endswith('id'): return f[:-2]+'ĭ'
    if f.endswith('ad'): return f[:-2]
    if f.endswith('d'): return f[:-1]
    return f
def strip_imp(f):
    if f.endswith('iñ'): return f[:-2]
    if f.endswith('ñ'): return f[:-1]
    return f

def build(lem,d):
    # returns dict of the 4 verb stems + noun stems, using all evidence in d
    S={}
    # IPFV_SG
    if 'V;IPFV;SG;PRS' in d: S['vsg']=d['V;IPFV;SG;PRS']
    elif 'V;IPFV;SG;FUT' in d: S['vsg']=strip_fut(d['V;IPFV;SG;FUT'])
    elif 'V;IMP;SG;PRS' in d: S['vsg']=strip_imp(d['V;IMP;SG;PRS'])
    else: S['vsg']=lem
    # IPFV_PL
    if 'V;IPFV;PL;PRS' in d: S['vpl']=d['V;IPFV;PL;PRS']
    elif 'V;IPFV;PL;FUT' in d: S['vpl']=strip_fut(d['V;IPFV;PL;FUT'])
    elif 'V;IMP;PL;PRS' in d: S['vpl']=strip_imp(d['V;IMP;PL;PRS'])
    else: S['vpl']=None
    S['psg']=d.get('V;PRF;SG;PRS')
    S['ppl']=d.get('V;PRF;PL;PRS')
    S['nsg']=d.get('N;SG',lem)
    S['npl']=d.get('N;PL')
    # reduplicates bit
    redbit=None
    for a,b in [('vsg','vpl'),('nsg','npl'),('psg','ppl')]:
        if S.get(a) and S.get(b):
            redbit = (S[a]!=S[b]); break
    S['redbit']=redbit
    return S

