    if S['ppl'] is not None: return S['ppl']
    if S['psg'] is not None:
        if S['redbit'] is False: return S['psg']
        return redup(S['psg'])
    # no perfective at all: derive from ipfv? fall back
    v=get_vpl(S); return v
def get_psg(S):
    if S['psg'] is not None: return S['psg']
    # derive from ppl by de-redup? hard; fall back to vsg (imperfective sg) 
    if S['ppl'] is not None:
        return S['ppl']  # weak
    return S['vsg']
def get_npl(S):
    if S['npl'] is not None: return S['npl']
    base=S['nsg']
    if S['redbit'] is False: return base
    return redup(base)

