# learn a singular->plural transform from a known pair; return callable
def learn_transform(sg,pl):
    if sg==pl:
        return ('id',None)
    if pl.endswith(sg):
        return ('prefix', pl[:len(pl)-len(sg)])
    # general: use opcodes to reconstruct; store the full edit script relative to sg
    sm=difflib.SequenceMatcher(a=sg,b=pl,autojunk=False)
